import{_ as e,o as t,c as r,a2 as o}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"供股","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/corporate-actions/rights-issue.md","filePath":"zh-CN/stock-trading/corporate-actions/rights-issue.md"}'),p={name:"stock-trading/corporate-actions/rights-issue.md"};function i(h,a,s,n,l,d){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="供股" tabindex="-1">供股 <a class="header-anchor" href="#供股" aria-label="Permalink to &quot;供股&quot;">​</a></h1><p>供股定义、股权来源、可交易与不可交易股权区别、行使方式及收费。</p><h2 id="什么是供股" tabindex="-1">什么是供股 <a class="header-anchor" href="#什么是供股" aria-label="Permalink to &quot;什么是供股&quot;">​</a></h2><p>供股是指上市公司发行新增股票让现有股东申购，股东可按其持股比例申购新股。如股东不参与供股，其权益将遭到稀释。</p><h2 id="什么是股权" tabindex="-1">什么是股权 <a class="header-anchor" href="#什么是股权" aria-label="Permalink to &quot;什么是股权&quot;">​</a></h2><p>股权是一种购买正股的权利，与正股对应。</p><p>股权的表现形态与普通股票一样，具有代码和名称及价格。股权的命名规则一般是：正股名称 +「股权」。</p><p>供股是根据股权持仓数量按照供股价购买对应数量的正股。会在供股权派发的 2-3 天内，在长桥 App 显示供股资料进行提交供股，App 操作仅支持提交一笔供股，在截止供股前可自行撤销重新提交。</p><p>例如：持有阿里港股股权 5,000 股，供股价是 100.00 港元，那么就可以申请以 500,000.00 港元的价格购买 5,000 股阿里港股。</p><h2 id="股权的来源" tabindex="-1">股权的来源 <a class="header-anchor" href="#股权的来源" aria-label="Permalink to &quot;股权的来源&quot;">​</a></h2><p>股票公司向所有持仓的股东派发股权，由交易所直接发放到股东账户（实物股票的需要到过户处办理手续才可以获得股权）。</p><p>此时正股的价格会下跌，下跌的价值刚好等于派发的股权价值。</p><h2 id="股权可交易与不可交易" tabindex="-1">股权可交易与不可交易 <a class="header-anchor" href="#股权可交易与不可交易" aria-label="Permalink to &quot;股权可交易与不可交易&quot;">​</a></h2><p>股权分为可交易和不可交易两种类型，由派发公司决定。</p><p>可交易的股权：与普通股票一样可以买卖，有价格波动。买入股权的客户可以申请供股。可交易供股权的代码规则为 029XX。</p><p>不可交易股权：客户只能选择是否供股，如果不供股，股权会清零。不可交易的代码规则为 44XXX。</p><h2 id="股权的生命周期" tabindex="-1">股权的生命周期 <a class="header-anchor" href="#股权的生命周期" aria-label="Permalink to &quot;股权的生命周期&quot;">​</a></h2><p>股权的生命节点包括：上市日、最后交易日、供股截止日、正股派送日。</p><p>可交易的股权一般只有 5-7 个交易日左右，上市日至最后交易日之间可以交易（长桥一般会在最后交易日前 2 天提前结束交易）。</p><p>上市日至供股截止日之间可以申请供股。供股时购买的正股在正股派送日进入持仓。</p><h2 id="股权的处理方式" tabindex="-1">股权的处理方式 <a class="header-anchor" href="#股权的处理方式" aria-label="Permalink to &quot;股权的处理方式&quot;">​</a></h2><p>可交易的股权：可选择卖出、供股、放任清零。</p><p>不可交易的股权：可选择供股、放任清零。</p><p>放任不管的结果是股权自动清零，客户会损失股权这部分资产。</p><h2 id="如何行使供股权" tabindex="-1">如何行使供股权 <a class="header-anchor" href="#如何行使供股权" aria-label="Permalink to &quot;如何行使供股权&quot;">​</a></h2><p>在行使供股权之前，长桥会通过系统消息、邮件方式通知所有股权持仓客户。</p><p>申请供股：长桥 APP - 资产 - 全部功能 - 供股要约 - 选需要供股标的提交申请供股。</p><h2 id="超额认购" tabindex="-1">超额认购 <a class="header-anchor" href="#超额认购" aria-label="Permalink to &quot;超额认购&quot;">​</a></h2><p>一般的供股行动允许客户认购超过其股权数量的股数。超额认购越多，需支付的资金越多。但超额认购并不代表客户一定可以获得其认购的股数，具体股数受上市公司决定。</p><p>例如客户原本持有 1,000 股股权，申请超额认购 10,000 股，最终结果可能为：仅拿到 1,000 股；或拿到 1,000 + 部分超额；或拿到 1,000 + 10,000 股。</p><h2 id="供股收费" tabindex="-1">供股收费 <a class="header-anchor" href="#供股收费" aria-label="Permalink to &quot;供股收费&quot;">​</a></h2><p>派发股权给客户和处理分红派息一样，会产生费用。</p><p>登记及过户费：1.5 港元/手，不足 1 手按 1 手收费。</p><p>分红服务费：按现金股息总额 0.2%，最低 30 港元。</p>',34)])])}const b=e(p,[["render",i]]);export{u as __pageData,b as default};
